// ============================================================
// Node: Validate Payload
// Garante que os campos obrigatórios estão presentes e corretos
// ============================================================
const input = $input.first().json;

const REQUIRED = ['type', 'priority', 'channel', 'correlation_id', 'content'];
const VALID_TYPES = ['goal_alert','own_goal_alert','penalty_alert','red_card_alert','second_yellow_alert','var_alert','match_start','match_end','match_halftime','operational_alert'];
const VALID_PRIORITIES = ['critical','high','medium','low'];
const VALID_CHANNELS = ['telegram','slack','email','webhook'];

const missing = REQUIRED.filter(f => !input[f]);
if (missing.length > 0) {
  throw new Error(`WF-07 payload inválido - campos ausentes: ${missing.join(', ')}`);
}

if (!VALID_TYPES.includes(input.type)) {
  throw new Error(`WF-07 tipo inválido: '${input.type}'. Válidos: ${VALID_TYPES.join(',')}`);
}
if (!VALID_PRIORITIES.includes(input.priority)) {
  throw new Error(`WF-07 prioridade inválida: '${input.priority}'`);
}
if (!VALID_CHANNELS.includes(input.channel)) {
  throw new Error(`WF-07 canal inválido: '${input.channel}'`);
}
if (!input.content?.body) {
  throw new Error('WF-07 content.body é obrigatório');
}

// Gera event_dedup_key para eventos ao vivo (previne duplicatas mesmo com retry)
let eventDedupKey = null;
if (input.match_id && input.event_type && input.event_minute !== undefined) {
  const raw = `${input.match_id}|${input.event_type}|${input.event_minute}|${input.channel}`;
  // Hash simples compatível com n8n sem crypto nativo acessível aqui
  // O hash real é calculado no node seguinte com Buffer
  eventDedupKey = Buffer.from(raw).toString('base64').substring(0, 128);
}

return [{
  json: {
    ...input,
    event_dedup_key: eventDedupKey,
    validated_at: new Date().toISOString(),
    execution_id: $execution.id,
  }
}];

// ============================================================
// Node: Rate Limit Decision
// Bloqueia notificações duplicadas por correlation_id no mesmo canal
// TTL de 60s para eventos críticos, 300s para medium/low
// ============================================================
const cacheResult = $input.first().json;
const payload = $('Validate Payload').first().json;

// Se a chave existe no Redis, já foi enviada recentemente
if (cacheResult.value) {
  return [{ json: { blocked: true, reason: 'rate_limited', payload } }];
}

return [{ json: { blocked: false, payload } }];

// Node executado quando rate limited - apenas loga e para
const { payload } = $input.first().json;
console.log(`[WF-07] Rate limited: ${payload.type} channel=${payload.channel} correlation=${payload.correlation_id}`);
return [];

// ============================================================
// Node: Format Message
// Gera o texto final da notificação com base no tipo de evento
// Todos os templates são definidos aqui - um único lugar para manutenção
// ============================================================
const { payload } = $input.first().json;
const c = payload.content;
const meta = c.metadata || {};

const FLAG_MAP = {
  'BRA': '????', 'ARG': '????', 'FRA': '????', 'ENG': '????',
  'ESP': '????', 'GER': '????', 'POR': '????', 'NED': '????',
  'ITA': '????', 'BEL': '????', 'URU': '????', 'COL': '????',
  'MEX': '????', 'USA': '????', 'JPN': '????', 'KOR': '????',
  'MAR': '????', 'SEN': '????', 'GHA': '????', 'EGY': '????',
  'CRO': '????', 'SRB': '????', 'DEN': '????', 'SUI': '????',
  'POL': '????', 'UKR': '????', 'WAL': '????', 'CAN': '????',
};

const homeFlag = FLAG_MAP[meta.home_code] || '???';
const awayFlag = FLAG_MAP[meta.away_code] || '???';
const scoreLine = meta.home_team ? `${homeFlag} *${meta.home_team}* ${meta.home_score ?? 0}–${meta.away_score ?? 0} *${meta.away_team}* ${awayFlag}` : '';

let formattedBody = '';

switch (payload.type) {

  case 'goal_alert':
    formattedBody = [
      `? *GOL!* - ${meta.minute}'`,
      scoreLine,
      ``,
      `?? *${meta.scorer || 'Jogador desconhecido'}*`,
      meta.assist ? `?? Assistência: ${meta.assist}` : null,
      meta.detail ? `?? ${meta.detail}` : null,
      ``,
      `#Copa2026${meta.home_code ? ` #${meta.home_code}` : ''}${meta.away_code ? ` #${meta.away_code}` : ''}`,
    ].filter(Boolean).join('\n');
    break;

  case 'own_goal_alert':
    formattedBody = [
      `?? *GOL CONTRA!* - ${meta.minute}'`,
      scoreLine,
      ``,
      `?? *${meta.scorer || 'Jogador desconhecido'}* (gol contra)`,
      ``,
      `#Copa2026${meta.home_code ? ` #${meta.home_code}` : ''}`,
    ].filter(Boolean).join('\n');
    break;

  case 'penalty_alert':
    formattedBody = [
      `?? *PÊNALTI CONVERTIDO!* - ${meta.minute}'`,
      scoreLine,
      ``,
      `? *${meta.scorer || 'Jogador desconhecido'}*`,
      ``,
      `#Copa2026${meta.home_code ? ` #${meta.home_code}` : ''}`,
    ].filter(Boolean).join('\n');
    break;

  case 'red_card_alert':
    formattedBody = [
      `?? *CARTÃO VERMELHO!* - ${meta.minute}'`,
      scoreLine,
      ``,
      `? *${meta.player || 'Jogador desconhecido'}* (${meta.team || '?'})`,
      meta.detail ? `?? ${meta.detail}` : null,
      ``,
      `#Copa2026${meta.home_code ? ` #${meta.home_code}` : ''}`,
    ].filter(Boolean).join('\n');
    break;

  case 'second_yellow_alert':
    formattedBody = [
      `???? *SEGUNDO AMARELO!* - ${meta.minute}'`,
      scoreLine,
      ``,
      `? *${meta.player || 'Jogador desconhecido'}* (${meta.team || '?'}) expulso`,
      ``,
      `#Copa2026${meta.home_code ? ` #${meta.home_code}` : ''}`,
    ].filter(Boolean).join('\n');
    break;

  case 'var_alert':
    formattedBody = [
      `?? *VAR REVISÃO* - ${meta.minute}'`,
      scoreLine,
      ``,
      `?? ${meta.detail || 'Decisão em análise pelo VAR'}`,
      ``,
      `#Copa2026${meta.home_code ? ` #${meta.home_code}` : ''}`,
    ].filter(Boolean).join('\n');
    break;

  case 'match_start':
    formattedBody = [
      `?? *INÍCIO DE JOGO!*`,
      scoreLine || `${homeFlag} ${meta.home_team || '?'} vs ${meta.away_team || '?'} ${awayFlag}`,
      ``,
      `??? ${meta.venue || 'Estádio não informado'}`,
      `?? Horário local: ${meta.local_time || '?'}`,
      ``,
      `#Copa2026${meta.home_code ? ` #${meta.home_code}` : ''}${meta.away_code ? ` #${meta.away_code}` : ''}`,
    ].filter(Boolean).join('\n');
    break;

  case 'match_halftime':
    formattedBody = [
      `?? *INTERVALO*`,
      scoreLine,
      ``,
      `?? Placar no intervalo: ${meta.home_score_ht ?? 0}–${meta.away_score_ht ?? 0}`,
      ``,
      `#Copa2026${meta.home_code ? ` #${meta.home_code}` : ''}`,
    ].filter(Boolean).join('\n');
    break;

  case 'match_end':
    formattedBody = [
      `?? *FIM DE JOGO!*`,
      scoreLine,
      ``,
      meta.winner ? `?? Vencedor: *${meta.winner}*` : `?? *Empate*`,
      ``,
      `#Copa2026${meta.home_code ? ` #${meta.home_code}` : ''}${meta.away_code ? ` #${meta.away_code}` : ''}`,
    ].filter(Boolean).join('\n');
    break;

  case 'operational_alert':
    formattedBody = [
      `?? *ALERTA OPERACIONAL*`,
      ``,
      c.title ? `*${c.title}*` : null,
      c.body,
      ``,
      `?? ${new Date().toISOString()}`,
    ].filter(Boolean).join('\n');
    break;

  default:
    formattedBody = c.body;
}

return [{
  json: {
    ...payload,
    formatted_body: formattedBody,
  }
}];

// ============================================================
// Node: Evaluate Send Result
// Consolida o resultado do envio (sucesso ou erro) em formato
// padronizado para o node de persistência
// ============================================================
const input = $input.first();
const payload = $('Format Message').first().json;

// n8n coloca erros no output de erro - se chegou aqui, foi sucesso
const success = !input.json?.error;
const errorMessage = input.json?.error?.message || null;

return [{
  json: {
    payload,
    send_success: success,
    send_error: errorMessage,
    sent_at: success ? new Date().toISOString() : null,
  }
}];

// ============================================================
// Node: Set Rate Limit Key
// Só define a chave de rate limit APÓS persistência bem-sucedida
// TTL varia por prioridade:
//   critical/high ? 60s (um por minuto no mesmo canal+correlation)
//   medium ? 300s
//   low ? 600s
// ============================================================
const result = $input.first().json;
const payload = $('Format Message').first().json;

const TTL_MAP = {
  critical: 60,
  high: 60,
  medium: 300,
  low: 600,
};

const ttl = TTL_MAP[payload.priority] || 60;

return [{
  json: {
    rate_limit_key: `wcic:rl:notify:${payload.channel}:${payload.correlation_id}`,
    rate_limit_ttl: ttl,
    notification_id: result.id,
    notification_status: result.status,
  }
}];

// ============================================================
// Node: Schedule Retry
// Notificações críticas/high são colocadas numa fila Redis
// para reprocessamento pelo WF-10 (Error Recovery)
// medium/low são apenas logadas como falha
// ============================================================
const evalResult = $('Evaluate Send Result').first().json;
const payload = evalResult.payload;

const retryPayload = {
  original_payload: payload,
  failure_reason: evalResult.send_error,
  failed_at: new Date().toISOString(),
  retry_count: 1,
};

// Só enfileira para retry se for alta prioridade
const shouldRetry = ['critical', 'high'].includes(payload.priority);

return [{ json: { ...retryPayload, should_retry: shouldRetry } }];

