={{ [
  $('Validate Payload').first().json.execution_id,
  $('Evaluate Send Result').first().json.send_success ? 'success' : 'error',
  $('Validate Payload').first().json.validated_at,
  $('Validate Payload').first().json.content?.metadata?.caller_workflow || 'unknown',
  $('Validate Payload').first().json.correlation_id,
  JSON.stringify({
    type: $('Validate Payload').first().json.type,
    channel: $('Validate Payload').first().json.channel,
    priority: $('Validate Payload').first().json.priority,
    send_success: $('Evaluate Send Result').first().json.send_success
  })
] }}
